import { useState } from "react";
import axios from "axios";

const EVENT_BOOKING_API = "http://127.0.0.1:5000/api/event-booking";

const EventBookingForm = () => {
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    event_date: "",
    event_type: "",
    guests: ""
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(EVENT_BOOKING_API, form);
      alert(res.data.message);
      setForm({
        name: "",
        email: "",
        phone: "",
        event_date: "",
        event_type: "",
        guests: ""
      });
    } catch (err) {
      console.error(err);
      alert("Error sending booking request");
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input name="name" placeholder="Name" value={form.name} onChange={handleChange} required />
      <input name="email" placeholder="Email" value={form.email} onChange={handleChange} required />
      <input name="phone" placeholder="Phone" value={form.phone} onChange={handleChange} required />
      <input type="date" name="event_date" value={form.event_date} onChange={handleChange} required />
      <input name="event_type" placeholder="Event Type" value={form.event_type} onChange={handleChange} required />
      <input type="number" name="guests" placeholder="Guests" value={form.guests} onChange={handleChange} required />
      <button type="submit">Send Event Request</button>
    </form>
  );
};

export default EventBookingForm;
